import json
import sys

results_file = "/root/.openclaw/workspace/quantized/runs/Qwen_Qwen3-1.7B-MXFP4/lm_eval_results/__root__.openclaw__workspace__quantized__Qwen_Qwen3-1.7B-MXFP4/results_2026-05-09T20-33-54.836309.json"

with open(results_file, 'r') as f:
    data = json.load(f)

results = data.get('results', {})

# Parse with comma-style keys
def get_acc(task_result):
    for key in ['acc,none', 'acc']:
        if key in task_result:
            return task_result[key]
    return None

def get_acc_stderr(task_result):
    for key in ['acc_stderr,none', 'acc_stderr']:
        if key in task_result:
            return task_result[key]
    return None

accuracy = {}
for task_name in ['piqa', 'mmlu', 'hellaswag']:
    if task_name in results:
        task_result = results[task_name]
        acc = get_acc(task_result)
        if acc is not None:
            accuracy[task_name] = {
                'accuracy': acc,
                'accuracy_stderr': get_acc_stderr(task_result)
            }
            print(f"{task_name}: acc={acc}, acc_stderr={get_acc_stderr(task_result)}")
        else:
            print(f"ERROR: No acc found for {task_name}", file=sys.stderr)
            print(f"  Keys: {list(task_result.keys())}", file=sys.stderr)

# Duration
duration = data.get('total_evaluation_time_seconds', None)
print(f"Duration seconds: {duration}")

